const main = require('../../lib/jibo-emotion-system');
let EmotionSystem = main.emotionSystem.EmotionSystem;
let EmotionName = main.common.EmotionName;
let EmotionTrace = main.emotion.EmotionTrace;
let EmotionPoint = main.common.EmotionPoint;
let TouchTypes = main.common.TouchTypes;
let Emotion = main.emotion.Emotion;
let ExpressionSystem = main.expression.ExpressionSystem;
const jibo = require('../../../jibo');

let es;

describe('Expression', () => {
    
    let sleepState;

    beforeEach(() => {
        es = new EmotionSystem();
        sleepState = jibo.action.types.SleepState.AWAKE;
        sinon.stub(jibo.action, 'getState', () => {
            return {
                time: new Date(),
                sleep: sleepState,
            };
        });
        return es.init({
            jibo: jibo
        });
    });

    afterEach(() => {
        jibo.action.getState.restore();
        es.dispose();
    });

   it('should instantiate without errors.', () => {
       expect(() => {
          return new ExpressionSystem(es);
       }).to.not.throw();
   });

   describe('#express', () => {
       it('should express from emotion trace on space update.', (done) => {
            sinon.stub(jibo.action, 'addPlayAnimationGoal', (data) => {
                jibo.action.addPlayAnimationGoal.restore();
                expect(data.category).to.equal('laughing');
                done();
            });
            const emoTrace = new EmotionTrace(null, null, new EmotionPoint(1, 1));
            es._emotionSpace.update(emoTrace);
       });

       it('should not express when asleep.', () => {
           const spy = sinon.spy(jibo.action, 'addPlayAnimationGoal');
           sleepState = jibo.action.types.SleepState.AWAKE;
           let emoTrace = new EmotionTrace(null, null, new EmotionPoint(1, 1));
           es._emotionSpace.update(emoTrace);
           expect(spy.callCount).to.equal(1);
           emoTrace = new EmotionTrace(null, null, new EmotionPoint(-2, -2));
           sleepState = jibo.action.types.SleepState.ASLEEP;
           es._emotionSpace.update(emoTrace);
           expect(spy.callCount).to.equal(1); // Should still just be one
           spy.restore();
       });

   });

    describe('#expressEmotion', () => {
        it('should not throw errors.', (done) => {
            sinon.stub(jibo.action, 'addPlayAnimationGoal', (data) => {
                jibo.action.addPlayAnimationGoal.restore();
                sinon.restore(jibo.action.addPlayAnimationGoal);
                expect(data.category).to.equal('politereply');
                done();
            });
            const exp = es._expressionSystem;
            const emo = new Emotion(EmotionName.NEUTRAL);
            exp.expressEmotion(emo);
        });
    });

    describe('#expressAnimation', () => {
        it('should not throw errors.', (done) => {
            sinon.stub(jibo.action, 'addPlayAnimationGoal', (data) => {
                jibo.action.addPlayAnimationGoal.restore();
                sinon.restore(jibo.action.addPlayAnimationGoal);
                expect(data.category).to.equal('HEAD_RIGHT');
                done();
            });
            const exp = es._expressionSystem;
            const options = {
                category: TouchTypes.HEAD_RIGHT,
                name: 'test touch',
                randomOrientation: false
            };
            exp.expressAnimation(options)
        });
    });

});
